Here's how to test `DataFetcher` with modern MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler("", HttpStatusCode.InternalServerError);
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)] // test itself times out after 5s
    public async Task FetchAsync_SlowServer_CompletesWithinTimeout()
    {
        // Pass TestContext.CancellationToken so the [Timeout] can
        // cancel the test cooperatively instead of thread-aborting.
        var handler = new FakeHandler("ok", HttpStatusCode.OK, delay: TimeSpan.FromMilliseconds(100));
        var fetcher = new DataFetcher(new HttpClient(handler));

        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        Assert.AreEqual("ok", result);
    }

    [TestMethod]
    public async Task FetchAsync_CallerCancels_ThrowsOperationCanceled()
    {
        // Arrange — token that is already cancelled
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        var handler = new FakeHandler("data", HttpStatusCode.OK,
            delay: TimeSpan.FromSeconds(10));
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                cts.Token));
    }

    // ── Fake handler to avoid real HTTP calls ──────────────────────
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public FakeHandler(string content, HttpStatusCode statusCode,
            TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(_delay, cancellationToken);
            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly`, works with nullability |
| `[Timeout] + _testContext.CancellationToken` | Cooperative cancellation — the timeout fires the token instead of thread-aborting |
| `Assert.ThrowsExactlyAsync<T>` | Modern replacement for `[ExpectedException]`; lets you inspect the exception |
| `FakeHandler` (not mocking `HttpClient`) | `HttpClient` can't be mocked directly; override `HttpMessageHandler.SendAsync` instead |
| Pre-cancelled `CancellationTokenSource` | Proves your code respects caller cancellation immediately |

The critical detail: **always flow `TestContext.CancellationToken`** into async calls inside `[Timeout]` tests. Without it, the timeout has no way to cooperatively stop your code and the test may hang.
